from smolagents.tools import tool
from pydantic import BaseModel, Field
from typing import Optional

class Ticket(BaseModel):
    customer_id: str = Field(..., description="Unique customer ID")
    issue: str = Field(..., max_length=500)
    priority: str = Field('medium', pattern='^(low|medium|high|critical)$')

class Order(BaseModel):
    order_id: str
    customer_email: str

@tool
def create_ticket(ticket: Ticket) -> str:
    """Create support ticket in Zendesk/Salesforce"""
    return f"Ticket #{12345} created for {ticket.customer_id}"

@tool
def lookup_order(order: Order) -> dict:
    """Retrieve order details from CRM"""
    return {'status': 'shipped', 'items': ['Widget A'], 'tracking': 'UPS123'}

def analyze_escalation(query: str) -> bool:
    triggers = ['refund all', 'complete outage', 'fraud alert', 'urgent billing']
    return any(trigger in query.lower() for trigger in triggers)

@tool
def escalate_to_human(customer_id: str, reason: str) -> str:
    """Escalate to human agent immediately"""
    return f"Escalated customer {customer_id}: {reason}"

